/* SPDX-License-Identifier: LGPL-3.0-or-later
 *
 * parsuna_rt: header-only runtime shared by every C parser generated by
 * parsuna.
 *
 * End users don't see this file — generated `<stem>.h` exposes its own
 * `<stem>_*` API, and the matching `<stem>.c` includes this header
 * internally so the whole runtime folds into the same translation unit
 * as the state machine. All names here are therefore plain (no prefix):
 * every symbol is `static inline` at file scope, so collisions only
 * matter within the one generated TU, and the generator takes care to
 * avoid them.
 */
#ifndef PARSUNA_RT_H
#define PARSUNA_RT_H

#include <stddef.h>
#include <stdint.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* ---------- types ---------- */

/* Source position: byte offset plus 1-based line/column. */
typedef struct { uint32_t offset, line, column; } Pos;

/* Half-open span [start, end) over the source. */
typedef struct { Pos start, end; } Span;

/* A lexed token: kind, span, and the matched text.
 *
 * `kind` is `uint16_t`. EOF = 0; grammar tokens get ids starting at 1; the
 * lexer emits `PARSUNA_LEX_ERROR` (0xFFFF) when it can't classify a
 * codepoint at the current position.
 *
 * `text` and `text_len` describe the matched bytes. In *reader* mode
 * (parser_init_from_read_fn) `text` is a fresh allocation owned by the
 * parser until the next call to parser_next, and is NUL-terminated.
 * In *string* mode (parser_init_from_string) `text` points directly into
 * the caller's source buffer — zero-copy and NOT NUL-terminated; read
 * exactly `text_len` bytes. Use `text_len` in both modes. */
typedef struct { uint16_t kind; Span span; char *text; size_t text_len; } Token;

/* A recoverable parse or lex error. `message` is owned by the parser
 * until the next call to parser_next. */
typedef struct { char *message; Span span; } Error;

/* Event discriminator: ENTER/EXIT delimit a rule subtree, TOKEN carries
 * a consumed structural token (including skips), GARBAGE is a token
 * dropped during error recovery (between an ERROR and its sync point),
 * ERROR is a recoverable diagnostic. */
typedef enum {
    EV_ENTER,
    EV_EXIT,
    EV_TOKEN,
    EV_GARBAGE,
    EV_ERROR
} EventTag;

/* Single parse event; inspect `tag` to decide which payload field to read. */
typedef struct {
    EventTag tag;
    int rule;
    Pos pos;
    Token token;
    Error error;
} Event;

/* Reader callback: fill up to `max` bytes into `out`, return number of
 * bytes written (0 for EOF, negative to signal an error). */
typedef int (*ReadFn)(void *ctx, char *out, int max);

/* End-of-input token kind. Always 0 — the runtime, generated code, and
 * consumers all rely on this constant. */
#define PARSUNA_TK_EOF ((uint16_t)0u)

/* Sentinel value that marks end of `sync` / FIRST sequence arrays.
 * Picked so it can never appear as a real entry: grammar token ids
 * are 1..N and EOF is 0, so 0xFFFF is unused. (Same value as
 * PARSUNA_LEX_ERROR, but the two are never compared in the same
 * context — sentinels live only inside arrays, the lex-failure kind
 * only appears as a Token.kind value.) */
#define SENTINEL ((uint16_t)0xFFFFu)

/* Lex-failure sentinel: the lexer emits a `Token` with this `kind` when
 * no DFA pattern matched at the current position. Distinct from any
 * grammar-declared token kind, so dispatch arms naturally fall through
 * to the recovery path. */
#define PARSUNA_LEX_ERROR ((uint16_t)0xFFFFu)

/* State id meaning "the parser has terminated". Reserved: real states
 * start at 1, so 0 is unambiguous. */
#define TERMINATED 0

/* ---------- monomorphization hooks ----------
 * The including translation unit (the generated `<stem>.c`) must supply
 * one constant before including this header so the runtime can size the
 * lookahead ring at compile time:
 *
 *   #define PARSUNA_K  <lookahead depth>
 *
 * plus file-scope definitions of:
 *
 *   static int  is_skip(uint16_t kind);
 *   static int  step(Parser *p, Event *out);
 *   static void longest_match_impl(const char *buf, size_t buf_len,
 *                                  size_t start, uint32_t mode,
 *                                  uint16_t *best_kind, size_t *best_len,
 *                                  size_t *scanned);
 *   static void apply_actions(uint16_t kind, struct Parser *p);
 *
 * `step` runs one state body and either fills `*out` and returns 1
 * (the state body emitted an event) or returns 0 (a pure transition
 * step — parser_next loops and calls `step` again).
 *
 * `apply_actions` runs the per-token mode-stack actions declared via
 * `-> push(name)` / `-> pop`. It's called once per token immediately
 * after the lexer hands it to the runtime, before the skip / lookahead
 * decision; grammars that declare no modes get an empty body. */
#ifndef PARSUNA_K
#  error "define PARSUNA_K before including parsuna_rt.h"
#endif

struct Parser;  /* fwd decl */
static int  is_skip(uint16_t kind);
static int  step(struct Parser *p, Event *out);
/* Compiled DFA: scans buf[start..buf_len] for the longest token in the
 * given lexer `mode`. On return, *best_kind/*best_len hold the longest
 * match (best_len == 0 means no accept), and *scanned is the total bytes
 * walked past start. The runtime uses `scanned == buf_len - start` to
 * detect that the scan ran out of buffer rather than hitting a real dead
 * transition. `mode` is `0` for the default (anonymous) mode; further ids
 * correspond to `@mode(name)` pre-annotations in declaration order. */
static void longest_match_impl(const char *buf, size_t buf_len, size_t start,
                               uint32_t mode, uint16_t *best_kind,
                               size_t *best_len, size_t *scanned);
static void apply_actions(uint16_t kind, struct Parser *p);

/* In-flight error recovery. Armed by `try_consume`'s slow path and by
 * `recover_to`; cleared once the lookahead lands on a sync token (or
 * EOF). Each call to parser_next advances recovery by exactly one
 * step, so a long run of unexpected input doesn't pile up — each
 * garbage token is yielded as its own EV_GARBAGE event. */
typedef struct {
    int active;
    /* `expected_set` is non-zero when the recovery was triggered by a
     * `try_consume` for `expected_kind`: if the sync set lands on
     * `expected_kind`, the recovery finalisation also consumes the
     * token (so the surrounding rule proceeds as if it had matched).
     * Zero for the dispatch error path, where there's no expected
     * kind to swallow on exit. */
    int expected_set;
    uint16_t expected_kind;
    /* Pointer into the static SYNC_<id> table emitted by codegen.
     * SENTINEL-terminated; not owned, so no free needed. */
    const uint16_t *sync;
} Recovery;

/* Parser state. */
typedef struct Parser {
    /* lexer state */
    ReadFn read_fn; void *read_ctx;
    char *buf; size_t buf_len, buf_cap, buf_pos;
    int eof;
    /* When set, `buf` is borrowed from the caller (parser_init_from_string):
     * no realloc, no memmove compaction, no per-token text allocation, and
     * parser_destroy does not free it. */
    int borrow_buf;
    uint32_t offset, line, col;

    /* parser state */
    Token look_buf[PARSUNA_K];           /* lookahead ring; size is a compile-time constant */
    int   look_filled[PARSUNA_K];        /* per-slot "holds a structural token" flag */
    Pos   prev_end;
    int   state;
    int   *ret; size_t ret_len, ret_cap;

    Recovery recovery;

    /* Lexer mode stack — top-of-stack is the active mode. Initialised
     * with the default mode (id 0) and never empty; `parser_pop_mode`
     * is a no-op when only the default remains, so a stray `-> pop`
     * action can't underflow. Push/pop is driven by the generated
     * `apply_actions` callback after each lex token. */
    uint32_t *mode_stack;
    size_t mode_top, mode_cap;

    /* When non-zero, skip tokens (whitespace, comments) are silently
     * consumed instead of yielded as EV_TOKEN events. The lexer still
     * matches them — they delimit structural tokens — but the
     * parser_next loop never returns them. Default 0, matching the
     * historic behaviour. */
    int drop_skips;

    /* Strings owned by the last yielded event. Freed at the top of the
     * next parser_next call so the caller can keep reading them until
     * they ask for a new event. */
    char *last_token_text;
    char *last_error_msg;
} Parser;

/* ---------- UTF-8 helper ---------- */

/* Write the codepoint at src[at..end] to *cp and return the byte length
 * consumed (1..4), or 1 if the byte is a continuation/garbage (advancing
 * by one is the right recovery step). */
static inline size_t utf8_decode(const char *src, size_t at, size_t end, uint32_t *cp) {
    if (at >= end) { *cp = 0; return 0; }
    unsigned char b0 = (unsigned char)src[at];
    if (b0 < 0x80) { *cp = b0; return 1; }
    if (b0 < 0xC0) { *cp = b0; return 1; }
    if (b0 < 0xE0) {
        if (at + 1 >= end) { *cp = b0; return 1; }
        *cp = ((b0 & 0x1F) << 6) | ((unsigned char)src[at + 1] & 0x3F);
        return 2;
    }
    if (b0 < 0xF0) {
        if (at + 2 >= end) { *cp = b0; return 1; }
        *cp = ((b0 & 0x0F) << 12) | (((unsigned char)src[at + 1] & 0x3F) << 6) | ((unsigned char)src[at + 2] & 0x3F);
        return 3;
    }
    if (at + 3 >= end) { *cp = b0; return 1; }
    *cp = ((b0 & 0x07) << 18)
        | (((unsigned char)src[at + 1] & 0x3F) << 12)
        | (((unsigned char)src[at + 2] & 0x3F) << 6)
        | ((unsigned char)src[at + 3] & 0x3F);
    return 4;
}

static inline int set_contains(const uint16_t *set, uint16_t k) {
    for (; *set != SENTINEL; set++) if (*set == k) return 1;
    return 0;
}

/* ---------- buffer / lexer helpers ---------- */

#define CHUNK 16384

static inline int lex_read_more(Parser *p) {
    if (p->eof) return 0;
    if (p->buf_cap - p->buf_len < CHUNK) {
        size_t new_cap = p->buf_cap ? p->buf_cap * 2 : (CHUNK * 2);
        while (new_cap - p->buf_len < CHUNK) new_cap *= 2;
        p->buf = (char*)realloc(p->buf, new_cap);
        p->buf_cap = new_cap;
    }
    int n = p->read_fn(p->read_ctx, p->buf + p->buf_len, (int)(p->buf_cap - p->buf_len));
    if (n <= 0) { p->eof = 1; return 0; }
    p->buf_len += (size_t)n;
    return 1;
}

static inline void lex_ensure(Parser *p, size_t want) {
    while (!p->eof && p->buf_len - p->buf_pos < want) {
        if (!lex_read_more(p)) break;
    }
}

/* Fast-path for pure ASCII non-newline slices; byte-by-byte walk when
 * the slice contains newlines or multi-byte UTF-8 sequences. */
static inline void lex_advance(Parser *p, size_t n) {
    size_t end = p->buf_pos + n;
    int needs_walk = 0;
    for (size_t k = p->buf_pos; k < end; k++) {
        unsigned char b = (unsigned char)p->buf[k];
        if (b == '\n' || b >= 0x80) { needs_walk = 1; break; }
    }
    if (!needs_walk) {
        p->col += (uint32_t)n;
        p->offset += (uint32_t)n;
        p->buf_pos = end;
    } else {
        while (p->buf_pos < end) {
            unsigned char b = (unsigned char)p->buf[p->buf_pos];
            p->buf_pos++; p->offset++;
            if (b == '\n') { p->line++; p->col = 1; }
            else if ((b & 0xC0) != 0x80) p->col++;
        }
    }
    /* Borrowed buffers must stay pinned so token texts remain valid; only
     * owned streaming buffers get compacted. */
    if (!p->borrow_buf && p->buf_pos > 65536) {
        memmove(p->buf, p->buf + p->buf_pos, p->buf_len - p->buf_pos);
        p->buf_len -= p->buf_pos;
        p->buf_pos = 0;
    }
}

static inline void longest_match(Parser *p, uint16_t *best_kind, int *best_len) {
    for (;;) {
        uint16_t bk;
        size_t bl, scanned;
        uint32_t mode = p->mode_stack[p->mode_top];
        longest_match_impl(p->buf, p->buf_len, p->buf_pos, mode, &bk, &bl, &scanned);
        size_t view_len = p->buf_len - p->buf_pos;
        if (!p->eof && scanned == view_len) {
            if (lex_read_more(p)) continue;
        }
        *best_kind = bk;
        *best_len = (int)bl;
        return;
    }
}

/* Build a token's text field. In borrow mode point into the source buffer
 * (zero-copy, not NUL-terminated). In owned mode malloc + memcpy + NUL. */
static inline char *make_text(Parser *p, size_t n) {
    if (p->borrow_buf) return p->buf + p->buf_pos;
    char *text = (char*)malloc(n + 1);
    memcpy(text, p->buf + p->buf_pos, n); text[n] = 0;
    return text;
}

static inline Token lex_next(Parser *p) {
    lex_ensure(p, CHUNK);
    if (p->buf_len - p->buf_pos == 0) {
        Pos pos = { p->offset, p->line, p->col };
        Token t = { PARSUNA_TK_EOF, { pos, pos }, NULL, 0 };
        return t;
    }
    uint16_t best_kind;
    int best_len;
    longest_match(p, &best_kind, &best_len);
    Pos start = { p->offset, p->line, p->col };
    if (best_len == 0) {
        uint32_t cp; size_t n = utf8_decode(p->buf, p->buf_pos, p->buf_len, &cp);
        if (n == 0) n = 1;
        char *text = make_text(p, n);
        lex_advance(p, n);
        Pos end = { p->offset, p->line, p->col };
        Token t = { PARSUNA_LEX_ERROR, { start, end }, text, n };
        return t;
    }
    char *text = make_text(p, (size_t)best_len);
    lex_advance(p, (size_t)best_len);
    Pos end = { p->offset, p->line, p->col };
    Token t = { best_kind, { start, end }, text, (size_t)best_len };
    return t;
}

/* ---------- mode stack ----------
 * Push/pop functions exposed to generated `apply_actions` so per-token
 * `-> push(name)` / `-> pop` annotations can swap which DFA `lex_next`
 * runs against. Push grows the backing array on demand; pop refuses to
 * underflow past the default mode (id 0) so a malformed grammar can't
 * crash the runtime. */
static inline void parser_push_mode(Parser *p, uint32_t mode) {
    if (p->mode_top + 1 >= p->mode_cap) {
        size_t new_cap = p->mode_cap ? p->mode_cap * 2 : 8;
        p->mode_stack = (uint32_t*)realloc(p->mode_stack, new_cap * sizeof(uint32_t));
        p->mode_cap = new_cap;
    }
    p->mode_stack[++p->mode_top] = mode;
}

static inline void parser_pop_mode(Parser *p) {
    if (p->mode_top > 0) p->mode_top--;
}

/* ---------- return stack ---------- */

static inline void ret_push(Parser *p, int s) {
    if (p->ret_len == p->ret_cap) {
        p->ret_cap = p->ret_cap ? p->ret_cap * 2 : 8;
        p->ret = (int*)realloc(p->ret, p->ret_cap * sizeof(int));
    }
    p->ret[p->ret_len++] = s;
}

/* ---------- public driver helpers (called from generated step()) ---------- */

static inline int get_state(const Parser *p) { return p->state; }
static inline void set_state(Parser *p, int s) { p->state = s; }
static inline void push_ret(Parser *p, int s) { ret_push(p, s); }
static inline int pop_ret(Parser *p) {
    if (p->ret_len > 0) return p->ret[--p->ret_len];
    return TERMINATED;
}
static inline Token look(const Parser *p, int i) { return p->look_buf[i]; }

static inline int matches_first(const Parser *p, const uint16_t *const *set) {
    for (const uint16_t *const *seq_p = set; *seq_p != NULL; seq_p++) {
        const uint16_t *seq = *seq_p;
        int ok = 1;
        for (int i = 0; seq[i] != SENTINEL; i++) {
            if (p->look_buf[i].kind != seq[i]) { ok = 0; break; }
        }
        if (ok) return 1;
    }
    return 0;
}

/* Build an Enter event for `rule`. Records the rule's start position so
 * a later Exit without any intervening tokens still yields a zero-width
 * span at the expected place. */
static inline Event ev_enter(Parser *p, int rule) {
    Pos pos = p->look_buf[0].span.start;
    p->prev_end = pos;
    Event e = {0};
    e.tag = EV_ENTER;
    e.rule = rule;
    e.pos = pos;
    return e;
}

/* Build an Exit event for `rule`, positioned at the end of the last
 * consumed token (or the rule's start for empty rules). */
static inline Event ev_exit(Parser *p, int rule) {
    Event e = {0};
    e.tag = EV_EXIT;
    e.rule = rule;
    e.pos = p->prev_end;
    return e;
}

/* Pop the current lookahead token and shift the buffer up by one. Slot
 * K-1 is left empty so pump-mode in parser_next can refill it (yielding
 * one skip per call) before the next step() reads lookahead. */
static inline Token take_token(Parser *p) {
    Token t = p->look_buf[0];
    p->prev_end = t.span.end;
    /* With PARSUNA_K as a compile-time constant the loop trivially
     * unrolls; for K=1 it degenerates away. */
    for (int i = 0; i < PARSUNA_K - 1; i++) {
        p->look_buf[i] = p->look_buf[i + 1];
        p->look_filled[i] = p->look_filled[i + 1];
    }
    p->look_filled[PARSUNA_K - 1] = 0;
    return t;
}

/* Consume the current lookahead token and return it as a TokenEvent.
 * Used on TryConsume's success path and on recovery's "synced-to-expected"
 * path — both yield legitimate parse data. */
static inline Event ev_consume(Parser *p) {
    Event e = {0};
    e.tag = EV_TOKEN;
    e.token = take_token(p);
    return e;
}

static inline Event ev_error_here(Parser *p, const char *msg) {
    Event e = {0};
    e.tag = EV_ERROR;
    e.error.message = strdup(msg);
    e.error.span.start = p->look_buf[0].span.start;
    e.error.span.end = p->look_buf[0].span.end;
    return e;
}

/* Try to consume a token of `kind`. On a hit returns a TokenEvent. On a
 * miss returns an ErrorEvent and arms recovery — subsequent parser_next
 * calls yield GarbageEvents until the lookahead lands on `sync` (when
 * it does, a matching token comes through as a normal TokenEvent).
 *
 * `sync` is typically the caller rule's FOLLOW set: recovery skips
 * unexpected tokens until the lookahead lands on one of these, which
 * gives the surrounding rule a reasonable place to resume. */
static inline Event try_consume(Parser *p, uint16_t kind, const uint16_t *sync, const char *name) {
    if (p->look_buf[0].kind == kind) return ev_consume(p);
    size_t nlen = strlen(name) + 16;
    char *msg = (char*)malloc(nlen);
    snprintf(msg, nlen, "expected %s", name);
    Event e = {0};
    e.tag = EV_ERROR;
    e.error.message = msg;
    e.error.span.start = p->look_buf[0].span.start;
    e.error.span.end = p->look_buf[0].span.end;
    p->recovery.active = 1;
    p->recovery.expected_set = 1;
    p->recovery.expected_kind = kind;
    p->recovery.sync = sync;
    return e;
}

/* Arm recovery-mode without an expected kind. Called from a dispatch
 * error leaf: the surrounding `cur` is already pointing at the
 * post-recovery state, and the ErrorEvent the caller pairs with this
 * call makes step() yield so recovery-mode can take over. */
static inline void recover_to(Parser *p, const uint16_t *sync) {
    p->recovery.active = 1;
    p->recovery.expected_set = 0;
    p->recovery.expected_kind = 0;
    p->recovery.sync = sync;
}

/* ---------- pump (next_event helper) ---------- */

/* True iff some lookahead slot still needs to be filled. Empty slots
 * are always a contiguous suffix — take_token parks the new empty at
 * index K-1 and pump_one fills the leftmost empty slot — so checking
 * slot K-1 is the O(1) form of "any slot is empty". */
static inline int pump_pending(const Parser *p) {
    return !p->look_filled[PARSUNA_K - 1];
}

/* ---------- lifecycle ---------- */

static inline void free_last(Parser *p) {
    /* Borrowed token text is pinned to the caller's buffer — never free it. */
    if (!p->borrow_buf) free(p->last_token_text);
    p->last_token_text = NULL;
    free(p->last_error_msg); p->last_error_msg = NULL;
}

/* Stamp the just-yielded event's owned strings so the next call to
 * parser_next can free them. Returns 1 so callers can `return yield_event(...)`. */
static inline int yield_event(Parser *p, Event ev, Event *out) {
    if (ev.tag == EV_TOKEN || ev.tag == EV_GARBAGE) {
        if (!p->borrow_buf) p->last_token_text = ev.token.text;
    } else if (ev.tag == EV_ERROR) {
        p->last_error_msg = ev.error.message;
    }
    *out = ev;
    return 1;
}

/* Shared initialization used by both init variants. Lookahead slots
 * start empty; the first call to parser_next enters pump-mode and
 * primes them, so any leading skip tokens (e.g. whitespace before the
 * first structural token) are emitted before the entry rule's Enter. */
static inline void parser_init_common(Parser *p, int entry_state) {
    p->line = 1;
    p->col = 1;
    p->state = entry_state;
    for (int i = 0; i < PARSUNA_K; i++) {
        p->look_filled[i] = 0;
    }
    /* prev_end starts at origin; ev_enter overwrites it once a real
     * token is in lookahead, so this only matters if the entry rule
     * exits without consuming anything. */
    Pos zero = { 0, 1, 1 };
    p->prev_end = zero;
    /* Mode stack starts with just the default mode (id 0). Grammars
     * without `@mode(...)` pre-annotations only ever see this single
     * entry; mode-using grammars push/pop via `apply_actions`. */
    p->mode_cap = 8;
    p->mode_stack = (uint32_t*)malloc(p->mode_cap * sizeof(uint32_t));
    p->mode_stack[0] = 0;
    p->mode_top = 0;
}

/* Initialize `p` for streaming over a `ReadFn` callback. */
static inline void parser_init_from_read_fn(Parser *p,
                                            int entry_state,
                                            ReadFn read_fn,
                                            void *ctx) {
    memset(p, 0, sizeof *p);
    p->read_fn = read_fn;
    p->read_ctx = ctx;
    parser_init_common(p, entry_state);
}

/* Initialize `p` for zero-copy lexing over an in-memory source buffer.
 *
 * The caller keeps ownership of `src`: the parser reads from it directly
 * and every Token's `text` points back into it. `src` must stay live and
 * unmodified until parser_destroy; its contents do not need to be
 * NUL-terminated. */
static inline void parser_init_from_string(Parser *p,
                                           int entry_state,
                                           const char *src,
                                           size_t len) {
    memset(p, 0, sizeof *p);
    /* Cast away const: we never write into the borrowed buffer. The
     * public Token.text is `char *` only for type-compatibility with
     * the reader path. */
    p->buf = (char *)src;
    p->buf_len = len;
    p->buf_cap = len;
    p->eof = 1;
    p->borrow_buf = 1;
    parser_init_common(p, entry_state);
}

/* Produce the next event from the parse, or 0 once the entire input
 * has been consumed.
 *
 * Each call runs in one of three modes — pump (refill lookahead,
 * possibly yielding a skip), recovery (one Garbage / synced-Token
 * event), or drive (one call to the generated step) — and yields at
 * most one event before the loop runs again. */
static inline int parser_next(Parser *p, Event *out) {
    free_last(p);
    for (;;) {
        if (pump_pending(p)) {
            Token t = lex_next(p);
            /* Apply per-token mode-stack actions before deciding skip vs.
             * structural — the parser-level check forbids `-> skip`
             * combined with `-> push/pop` so a skip token never has
             * actions, but calling unconditionally keeps the call site
             * simple and the default impl is empty for action-free
             * grammars. */
            apply_actions(t.kind, p);
            if (is_skip(t.kind)) {
                if (!p->drop_skips) {
                    Event e = {0};
                    e.tag = EV_TOKEN;
                    e.token = t;
                    return yield_event(p, e, out);
                }
                /* Skip-drop mode: free the token text we just allocated
                 * (in owned-buffer mode) and loop without filling the
                 * lookahead. Borrowed-buffer mode never allocates here. */
                if (!p->borrow_buf) free(t.text);
                continue;
            }
            for (int i = 0; i < PARSUNA_K; i++) {
                if (!p->look_filled[i]) {
                    p->look_buf[i] = t;
                    p->look_filled[i] = 1;
                    break;
                }
            }
            continue;
        }
        if (p->recovery.active) {
            uint16_t k = p->look_buf[0].kind;
            int synced = (k == PARSUNA_TK_EOF) || set_contains(p->recovery.sync, k);
            if (synced) {
                int was_expected = p->recovery.expected_set && p->recovery.expected_kind == k;
                p->recovery.active = 0;
                if (was_expected) return yield_event(p, ev_consume(p), out);
                continue;
            }
            Event e = {0};
            e.tag = EV_GARBAGE;
            e.token = take_token(p);
            return yield_event(p, e, out);
        }
        if (p->state == TERMINATED) {
            /* EOF gate. On the first visit with trailing input, raise
             * an error and arm a sync-empty recovery so the rest of
             * the input drains as Garbage events one per call. Once
             * recovery has eaten its way to EOF the lookahead pins
             * at EOF (the lexer keeps yielding it), so this is
             * naturally idempotent — subsequent visits just return 0. */
            if (p->look_buf[0].kind == PARSUNA_TK_EOF) return 0;
            static const uint16_t empty_sync[] = { SENTINEL };
            Event e = ev_error_here(p, "expected end of input");
            p->recovery.active = 1;
            p->recovery.expected_set = 0;
            p->recovery.expected_kind = 0;
            p->recovery.sync = empty_sync;
            return yield_event(p, e, out);
        }
        Event e;
        if (step(p, &e)) return yield_event(p, e, out);
    }
}

static inline void parser_destroy(Parser *p) {
    if (!p) return;
    if (!p->borrow_buf) free(p->buf);
    free(p->ret);
    free(p->mode_stack);

    /* look_buf is an inline fixed-size array — no free. Free each
     * filled slot's owned text (skipped in borrow mode). */
    if (!p->borrow_buf) {
        for (int i = 0; i < PARSUNA_K; i++) {
            if (p->look_filled[i]) free(p->look_buf[i].text);
        }
    }
    free_last(p);
}

#endif
